window.dataLayer=window.dataLayer||[];const campoBusqueda=document.getElementById("text-search");function debounce(fn,delay){let timeout;return(...args)=>{clearTimeout(timeout);timeout=setTimeout(()=>fn(...args),delay)}}function normalizeText(input){if(!input)return"";let s=input.trim().toLowerCase();s=s.normalize("NFD").replace(/[\u0300-\u036f]/g,"");s=s.replace(/ñ/g,"n");s=s.replace(/[^a-z0-9\s]/g,"");s=s.replace(/\s+/g," ").trim();if(s.length>100)s=s.slice(0,100);return s}const handler=debounce(function(event){const raw=event.target.value||"";const valor=normalizeText(raw);if(!valor)return;window.dataLayer.push({event:"search_input_completed",field_id:"text-search",field_value_normalized:valor,char_length:valor.length,word_count:valor.split(/\s+/).filter(Boolean).length});console.log("dataLayer push:",valor)},800);if(campoBusqueda){campoBusqueda.addEventListener("input",handler);campoBusqueda.addEventListener("change",e=>{const valor=normalizeText(e.target.value||"");if(!valor)return;window.dataLayer.push({event:"view_search_results",button_name:"resultado busqueda",id_event:"",id_journey:"experiencia",id_multiproduct_journey:"yape web",field_id:"text-search",search_term:"texto ingresado",search_result:valor})})}else{}